/* fsm.c — USART 协议解析器，STM32 HAL 环境 */
#include <stdint.h>

typedef enum { FSM_SYNC = 0, FSM_HDR, FSM_DATA, FSM_CRC, FSM_DONE, FSM_ERR } FsmState;
typedef enum { EVT_BYTE = 0, EVT_TIMEOUT, EVT_RESET } FsmEvent;

static FsmState cur = FSM_SYNC;
static uint8_t  rx_buf[128], rx_len = 0;
static uint16_t crc_val = 0;

static void do_clear(void) { rx_len = 0; crc_val = 0; }
static void do_crc(uint8_t b) { crc_val = crc16_update(crc_val, b); }

static const struct { FsmState c; FsmEvent e; FsmState n; void (*enter)(uint8_t); } T[] = {
    {FSM_SYNC, EVT_BYTE, FSM_HDR,   NULL},
    {FSM_HDR,  EVT_BYTE, FSM_DATA,  NULL},
    {FSM_DATA, EVT_BYTE, FSM_DATA,  do_crc},
    {FSM_DATA, EVT_TIMEOUT, FSM_ERR, do_clear},
    {FSM_DONE, EVT_BYTE, FSM_HDR,   do_clear},
    {FSM_ERR,  EVT_RESET, FSM_SYNC, do_clear},
};

static void fsm_set(FsmState s) { cur = s; __DSB(); __ISB(); }

void fsm_advance(FsmEvent evt, uint8_t byte) {
    for (size_t i = 0; i < sizeof(T)/sizeof(T[0]); i++) {
        if (T[i].c == cur && T[i].e == evt) {
            if (T[i].enter) T[i].enter(byte);
            fsm_set(T[i].n);
            return;
        }
    }
}
/* HAL 回调中调用: fsm_advance(EVT_BYTE, byte) — 不直接写 cur */
