/* ERROR 状态恢复 + 覆盖率检查 */
#include <stdint.h>
#include <stdbool.h>

typedef enum {
    FSM_SYNC = 0, FSM_HEADER, FSM_DATA, FSM_CRC,
    FSM_COMPLETE, FSM_ERROR, FSM_STATE_COUNT
} FsmState;

static uint32_t error_tick = 0;
static const uint32_t ERROR_TIMEOUT_MS = 500;

static void fsm_error_update(void) {
    error_tick++;
    if (error_tick >= ERROR_TIMEOUT_MS) {
        error_tick = 0;
        fsm_set_state(FSM_SYNC);  /* 超时恢复 */
    }
}

/* 编译时覆盖率检查 */
static void test_fsm_exit_coverage(void) {
    bool has_exit[FSM_STATE_COUNT] = {false};
    for (size_t i = 0; i < TRANS_COUNT; i++) {
        has_exit[trans_table[i].cur] = true;
    }
    for (int s = 0; s < FSM_STATE_COUNT; s++) {
        if (!has_exit[s]) __BKPT(0);  /* 死锁状态，调试时断点 */
    }
}
