typedef enum { FSM_SYNC = 0, FSM_HDR, FSM_DATA, FSM_CRC, FSM_OK, FSM_ERR, FSM_CNT } FsmState;
static FsmState cur = FSM_SYNC;

static void do_clear(void)  { len = 0; crc = 0; }
static void do_dispatch()   { handle_frame(rx_buf, len); }

static const struct { FsmState c; uint8_t e; FsmState n; void (*f)(void); } T[] = {
    {FSM_SYNC, 0xAA, FSM_HDR,   NULL},
    {FSM_HDR,  0x55, FSM_DATA,  do_clear},
    {FSM_HDR,  0x00, FSM_SYNC,  NULL},
    {FSM_DATA, 0x00, FSM_DATA,  NULL},
    {FSM_CRC,  0x00, FSM_OK,    do_dispatch},
    {FSM_OK,   0x00, FSM_SYNC,  do_clear},
    {FSM_ERR,  0x00, FSM_SYNC,  do_clear},
};

static void fsm_set(FsmState s) { cur = s; __DSB(); __ISB(); }

void fsm_step(uint8_t b) {
    for (size_t i = 0; i < sizeof(T)/sizeof(T[0]); i++) {
        if (T[i].c == cur && (T[i].e == 0x00 || T[i].e == b)) {
            if (T[i].f) T[i].f();
            fsm_set(T[i].n);
            return;
        }
    }
}
